#!/usr/bin/env python3
"""
deploy_v19_34_221.py - (B) L2 max_slots env-config + IB-309 cap watch
                       (C) Technical pillar ma_stack from EMA alignment

B (services/l2_router.py): _MAX_L2_SLOTS now reads MAX_L2_SLOTS env (default 3);
   adds an IB-Error-309 / pusher-cap watch (cap_rejections + last_cap_skipped in
   /api/l2-router/status, WARN log when the pusher rejects an L2 add). This
   deploy also appends MAX_L2_SLOTS=6 to backend/.env if absent.
   >> YOU MUST ALSO raise the Windows pusher's own max_slots from 3 to 6 (and
      ensure the IB market-depth entitlement allows 6) or the extra slots will
      be rejected (309) — now visible in l2-router status, no silent thrash.

C (services/tqs/technical_quality.py): ma_stack derived from the EMA stack
   (EMA9>EMA20>EMA50, price above EMA50) instead of the conservative intraday
   `trend`, which pinned ma_stack neutral ~78%. Holds through intraday pullbacks.

SAFETY: each service file is a checksum-guarded full-file replace (writes ONLY
if the on-disk file matches the pre-patch HEAD sha OR already carries the v221
marker; aborts on drift WITHOUT changing anything). Idempotent, transactional,
runs both tests, commits + pushes BEFORE restart.

RUN ON THE DGX:
  curl -s https://paste.rs/XXXXX -o /tmp/deploy_v19_34_221.py
  python3 /tmp/deploy_v19_34_221.py
  ./start_backend.sh --force
"""
import os, base64, hashlib, json, shutil, subprocess, sys, py_compile

REPO=os.path.expanduser("~/Trading-and-Analysis-Platform")
if not os.path.isdir(REPO): REPO=os.getcwd()
CFG=json.loads(r"""{"marker": "v19.34.221", "svc": {"backend/services/l2_router.py": {"pre": "9e0197263ef0246143e1382b51d73d435238d8f757a7851cd22bce92fc9cae9a", "new_sha": "0dac6adac80553d7fc9e1262cc1769b0aa34d17314f5d9b0c2dbfe628ae713cf", "b64": ""}, "backend/services/tqs/technical_quality.py": {"pre": "64d247579f0af1fe266474bb274294491f1b1881d445b53e1722df9de21f28f5", "new_sha": "2dea8604e58e293d250eed43256e46f6a8137f98fe678c7193e68334753f0811", "b64": ""}}, "tests": {"backend/tests/test_v19_34_221_ma_stack_alignment.py": "", "backend/tests/test_v19_34_221_l2_slots.py": ""}}""")
MARKER=CFG["marker"]


def fail(m):
    print("\n[FAIL] "+m); sys.exit(1)


def apply_svc(rel, info):
    path=os.path.join(REPO, rel)
    if not os.path.isfile(path): fail("target not found: "+path)
    cur=open(path,"rb").read(); cur_sha=hashlib.sha256(cur).hexdigest()
    new_bytes=base64.b64decode(info["b64"])
    assert hashlib.sha256(new_bytes).hexdigest()==info["new_sha"], "payload corrupt: "+rel
    if MARKER in cur.decode("utf-8","ignore"):
        print(f"[ok] {rel}: already patched (marker) - skip."); return
    if cur_sha != info["pre"]:
        fail(f"{rel}: matches NEITHER pre-patch sha NOR marker (sha={cur_sha[:12]}). "
             "Drift - aborting WITHOUT changes.")
    shutil.copy2(path, path+".v221.bak"); open(path,"wb").write(new_bytes)
    try:
        py_compile.compile(path, doraise=True)
    except py_compile.PyCompileError as e:
        shutil.copy2(path+".v221.bak", path); fail(f"{rel}: py_compile failed, rolled back: {e}")
    os.remove(path+".v221.bak")
    print(f"[ok] {rel}: replaced + compiles clean.")


def main():
    print("== deploy_v19_34_221 ==\nrepo: "+REPO)
    for rel, info in CFG["svc"].items():
        apply_svc(rel, info)
    for rel, b64 in CFG["tests"].items():
        p=os.path.join(REPO, rel); os.makedirs(os.path.dirname(p), exist_ok=True)
        open(p,"wb").write(base64.b64decode(b64)); print("[ok] wrote "+rel)

    # append MAX_L2_SLOTS=6 to backend/.env if absent (single-line append; no rewrite)
    envp=os.path.join(REPO,"backend",".env")
    try:
        cur = open(envp).read() if os.path.isfile(envp) else ""
        if "MAX_L2_SLOTS" not in cur:
            with open(envp,"a") as f:
                if cur and not cur.endswith("\n"): f.write("\n")
                f.write("MAX_L2_SLOTS=6\n")
            print("[ok] appended MAX_L2_SLOTS=6 to backend/.env")
        else:
            print("[ok] MAX_L2_SLOTS already present in backend/.env - left as-is")
    except Exception as e:
        print("[warn] could not edit backend/.env (set MAX_L2_SLOTS=6 manually):", e)

    print("\n== pytest ==")
    tlist=[os.path.join(REPO, t) for t in CFG["tests"]]
    r=subprocess.run([sys.executable,"-m","pytest", *tlist, "-q"], cwd=os.path.join(REPO,"backend"))
    if r.returncode!=0: fail("pytest failed - NOT committing.")
    print("[ok] tests green.")

    print("\n== git commit + push ==")
    subprocess.run(["git","add","-A"],cwd=REPO)
    cm=subprocess.run(["git","commit","-m",
        "v19.34.221 (B) L2 MAX_L2_SLOTS env + IB-309 cap watch; "
        "(C) Technical ma_stack from EMA alignment"],cwd=REPO)
    if cm.returncode==0:
        subprocess.run(["git","push"],cwd=REPO); print("[ok] committed + pushed.")
    else:
        print("[info] nothing to commit - skipping push.")

    print("\n[DONE] Restart backend:  ./start_backend.sh --force")
    print("\n>>> ACTION REQUIRED for the L2 bump to take effect end-to-end:")
    print("    1. On the WINDOWS pusher, raise its max L2 slots from 3 to 6.")
    print("    2. Confirm your IB market-depth entitlement allows 6 simultaneous.")
    print("    Then watch:  curl -s localhost:8001/api/l2-router/status | python3 -m json.tool")
    print("    If 'cap_rejections' climbs / 'last_cap_skipped' is non-empty, IB/")
    print("    pusher is still capping below 6 (Error 309) — lower MAX_L2_SLOTS.")
    print("\nVerify ma_stack (C) after ~15 min:")
    print("    python3 /tmp/diag_tqs_pillar_breakdown.py --since-min 15")
    print("    (ma_stack 'neutral' default-rate should DROP from ~78%.)")


if __name__=="__main__":
    main()
